      nativeTokenLimit: params.permissions?.nativeTokenLimit ?? params.nativeTokenLimit ?? "0",
      erc20TokenLimit:  (params.permissions?.erc20TokenLimit && typeof params.permissions.erc20TokenLimit === 'object')
